concepts.content:
App Router 的核心区分：

// 默认是 Server Component — 不加 "use client"
// ✅ 可以：直接访问数据库、读取文件、零 JS 体积
// ❌ 不能：useState、useEffect、事件处理

async function Page() {
  const data = await db.query("SELECT * FROM users");  // 直接查 DB！
  return <UserList users={data} />;
}

// "use client" 声明 Client Component
"use client";
import { useState } from "react";

function Counter() {
  const [count, setCount] = useState(0);  // ✅ 可以用 Hook
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}

💡 规则：能用 Server 就用 Server，交互组件才用 Client

App Router 中的数据获取方式：

1. Server Component 直接 async
   async function Page() {
     const users = await fetch("https://api.example.com/users");
     return <UserList users={users} />;
   }

2. 缓存策略
   fetch(url, { cache: "force-cache" });   // 缓存（默认）
   fetch(url, { cache: "no-store" });      // 不缓存
   fetch(url, { next: { revalidate: 60 } }); // 60秒后重新验证

3. Server Actions（表单提交）
   async function createUser(formData: FormData) {
     "use server";
     await db.user.create({ name: formData.get("name") });
   }

   <form action={createUser}>
     <input name="name" />
     <button type="submit">提交</button>
   </form>

💡 Server Actions 替代了传统的 API Route + fetch 模式

