concepts.content:
JSON Schema 驱动 UI 渲染：

Schema 结构：
{
  type: "Page",
  children: [
    { type: "Button", props: { text: "提交", type: "primary" } },
    { type: "Table", props: { columns: [...], data: [...] } }
  ]
}

渲染器：
function Renderer({ schema }) {
  const Component = componentMap[schema.type];
  return (
    <Component {...schema.props}>
      {schema.children?.map(child =>
        <Renderer key={child.id} schema={child} />
      )}
    </Component>
  );
}

💡 递归渲染 — Schema 树 = 组件树

codeExamples.code:
// schema.ts — 页面描述
interface SchemaNode {
  id: string;
  type: string;         // 组件类型
  props?: Record<string, any>;
  children?: SchemaNode[];
}

const pageSchema: SchemaNode = {
  id: "root",
  type: "Page",
  children: [
    { id: '1', type: 'Input', props: { label: '姓名', placeholder: '请输入' } },
    { id: '2', type: 'Input', props: { label: '邮箱', type: 'email' } },
    { id: '3', type: 'Button', props: { text: '提交', type: 'primary' } },
  ],
};

// renderer.tsx — Schema 渲染器
import { Input, Button } from 'antd';

const componentMap: Record<string, React.ComponentType<any>> = {
  Page: ({ children }) => <div className="page">{children}</div>,
  Input: (props) => <Input {...props} />,
  Button: ({ text, ...props }) => <Button {...props}>{text}</Button>,
};

function Renderer({ schema }: { schema: SchemaNode }) {
  const Component = componentMap[schema.type];
  if (!Component) return <div>未知组件: {schema.type}</div>;

  return (
    <Component {...schema.props}>
      {schema.children?.map(child => (
        <Renderer key={child.id} schema={child} />
      ))}
    </Component>
  );
}

// 使用
function App() {
  return <Renderer schema={pageSchema} />;
}

concepts.content:
React + WASM 集成模式：

1. 初始化 WASM 模块
   const wasm = await init();

2. 在 React 中使用
   useEffect(() => {
     init().then(setWasm);
   }, []);

3. Web Worker 运行 WASM
   长计算放入 Worker → 不阻塞 UI

4. 性能对比
   简单计算 → JS 更快（WASM 有调用开销）
   复杂计算 → WASM 快 2-10 倍

💡 只在 JS 性能不够时才用 WASM — 不要过早优化

codeExamples.code:
// Rust: src/lib.rs
use wasm_bindgen::prelude::*;

#[wasm_bindgen]
pub fn fibonacci(n: u32) -> u64 {
    if n <= 1 { return n as u64; }
    let (mut a, mut b) = (0u64, 1u64);
    for _ in 2..=n {
        let temp = a + b;
        a = b;
        b = temp;
    }
    b
}

#[wasm_bindgen]
pub fn process_image(data: &[u8], width: u32) -> Vec<u8> {
    // 图像灰度处理（WASM 速度优势明显）
    data.chunks(4)
        .flat_map(|rgba| {
            let gray = (rgba[0] as f32 * 0.299
              + rgba[1] as f32 * 0.587
              + rgba[2] as f32 * 0.114) as u8;
            vec![gray, gray, gray, rgba[3]]
        })
        .collect()
}

// React: useWasm.ts
import { useState, useEffect } from 'react';
import init, { fibonacci, process_image } from 'my-wasm';

export function useWasm() {
  const [ready, setReady] = useState(false);
  useEffect(() => {
    init().then(() => setReady(true));
  }, []);
  return { ready, fibonacci, process_image };
}

// 使用
function CalcComponent() {
  const { ready, fibonacci } = useWasm();
  if (!ready) return <div>加载 WASM...</div>;
  return <div>fib(40) = {fibonacci(40)}</div>;
}

