function Dashboard({ data }) {
  const stats = useMemo(() => {
    // 复杂计算只在 data 变化时重新执行
    return data.reduce((acc, item) => {
      acc.total += item.value;
      acc.count++;
      return acc;
    }, { total: 0, count: 0 });
  }, [data]);
  return <div>平均: {stats.total / stats.count}</div>;
}

