// 1. 文档入库
async function indexDocument(doc: string) {
  const chunks = splitText(doc, { chunkSize: 800, overlap: 100 });
  for (const chunk of chunks) {
    const embedding = await openai.embeddings.create({
      model: "text-embedding-3-small",
      input: chunk,
    });
    await vectorDB.upsert({ id: uuid(), vector: embedding, text: chunk });
  }
}

// 2. 查询
async function askQuestion(question: string) {
  const qEmbedding = await openai.embeddings.create({
    model: "text-embedding-3-small",
    input: question,
  });
  const relevantChunks = await vectorDB.search(qEmbedding, { topK: 5 });
  const context = relevantChunks.map(c => c.text).join("

");

  const answer = await openai.chat.completions.create({
    model: "gpt-4",
    messages: [
      { role: "system", content: "基于以下资料回答问题：
" + context },
      { role: "user", content: question },
    ],
  });
  return answer.choices[0].message.content;
}

concepts.content:
LLM 决定调用什么工具：

const tools = [
  { name: "search", description: "搜索文档" },
  { name: "calculator", description: "计算数学表达式" },
];

LLM 返回：{ tool: "search", args: { query: "React hooks" } }
程序执行工具并返回结果
LLM 基于结果继续推理

codeExamples.code:
interface Tool {
  name: string;
  description: string;
  execute: (args: any) => Promise<string>;
}

async function agentLoop(question: string, tools: Tool[]) {
  const messages = [
    { role: "system", content: "你是一个智能助手，可以使用工具回答问题。" },
    { role: "user", content: question },
  ];

  while (true) {
    const response = await llm.chat(messages, { tools });

    if (response.content) return response.content; // 最终答案

    // LLM 要调用工具
    const toolCall = response.toolCalls[0];
    const tool = tools.find(t => t.name === toolCall.name);
    const result = await tool.execute(toolCall.args);

    messages.push(
      { role: "assistant", content: null, toolCalls: [toolCall] },
      { role: "tool", name: toolCall.name, content: result },
    );
  }
}

