import { Cron, Interval, Timeout } from '@nestjs/schedule';

@Injectable()
export class TaskService {
  private readonly logger = new Logger(TaskService.name);

  // 每天 9:00 发送日报
  @Cron('0 0 9 * * 1-5', { name: 'dailyReport' })
  async sendDailyReport() {
    const start = Date.now();
    this.logger.log('开始生成日报...');
    try {
      const report = await this.generateReport();
      await this.emailService.send(report);
      this.logger.log(`日报发送完成，耗时 ${Date.now() - start}ms`);
    } catch (err) {
      this.logger.error('日报发送失败', err.stack);
      await this.alertService.notify('日报任务失败', err.message);
    }
  }

  // 每 5 分钟清理过期缓存
  @Interval(5 * 60 * 1000)
  async cleanExpiredCache() {
    const count = await this.cacheService.cleanExpired();
    if (count > 0) this.logger.log(`清理 ${count} 条过期缓存`);
  }

  // 应用启动 10 秒后预热缓存
  @Timeout(10 * 1000)
  async warmUpCache() {
    this.logger.log('开始缓存预热...');
    await this.cacheService.warmUp();
