// Mongoose Schema 定义（Node.js）
import mongoose from 'mongoose';

const userSchema = new mongoose.Schema({
  name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  age: { type: Number, min: 0 },
  tags: [String],
  createdAt: { type: Date, default: Date.now },
});

const User = mongoose.model('User', userSchema);

// CRUD 操作
await User.create({ name: '小明', email: 'xm@test.com', age: 25 });
const users = await User.find({ age: { $gte: 18 } }).sort({ age: -1 });
await User.updateOne({ name: '小明' }, { $set: { age: 26 } });
await User.deleteOne({ name: '小明' });

// 聚合管道
const stats = await User.aggregate([
  { $match: { age: { $gte: 18 } } },
  { $group: { _id: null, avgAge: { $avg: '$age' }, count: { $sum: 1 } } },
]);

// Redis 缓存层（Node.js）
import Redis from 'ioredis';
const redis = new Redis();

// 缓存用户数据
async function getUserWithCache(id: string) {
  const cached = await redis.get(`user:${id}`);
  if (cached) return JSON.parse(cached);  // 缓存命中

  const user = await User.findById(id);
  if (user) {
    await redis.set(`user:${id}`, JSON.stringify(user), 'EX', 3600);  // 1小时过期
  }
  return user;
}

