async function getUserOrders(userId: string) {
  const user = await db.user.findUnique({ where: { id: userId } });
  const orders = await db.order.findMany({ where: { userId } });
  for (const order of orders) {
    order.items = await db.orderItem.findMany({
      where: { orderId: order.id }
    });
  }
  return { user, orders };
}

// AI 评审结果（按维度）
// 🚨 正确性: user 可能为 null，需要判断
// 🚨 性能: N+1 查询！循环中查询 orderItems
// ⚠️ 健壮性: 缺少 try/catch 错误处理
// ⚠️ 安全性: 没有校验 userId 是否属于当前用户

// 修复后
async function getUserOrders(userId: string, currentUserId: string) {
  // 安全性：校验权限
  if (userId !== currentUserId) {
    throw new ForbiddenException('无权访问');
  }

  try {
    const user = await db.user.findUnique({ where: { id: userId } });
    if (!user) throw new NotFoundException('用户不存在');  // 正确性

    // 性能：用 include 替代 N+1
    const orders = await db.order.findMany({
      where: { userId },
      include: { items: true },  // 一次查询获取关联数据
    });

    return { user, orders };
  } catch (error) {
    // 健壮性：统一错误处理
    if (error instanceof HttpException) throw error;
    throw new InternalServerErrorException('获取订单失败');
  }
}

