  const users = await db.user.findMany();
  const userCount = users.length;
  const orders = await db.order.findMany();
  const orderCount = orders.length;
  const revenue = orders.reduce((sum, o) => sum + o.total, 0);
  const products = await db.product.findMany();
  const productCount = products.length;
  return { userCount, orderCount, revenue, productCount };
}

// 问题：1) N+1 查询 2) 全量查询 3) 无缓存 4) 无错误处理

// 重构后的代码
// Prompt: "重构 getDashboard：
// 1. 用聚合查询替代全量查询
// 2. 添加 Redis 缓存（5 分钟过期）
// 3. 添加错误处理
// 4. 保持功能不变"

async function getDashboard() {
  const cacheKey = 'dashboard:stats';

  // 尝试缓存
  const cached = await redis.get(cacheKey);
  if (cached) return JSON.parse(cached);

  try {
    // 聚合查询替代全量
    const [userStats, orderStats, productStats] = await Promise.all([
      db.user.aggregate({ _count: true }),
      db.order.aggregate({ _count: true, _sum: { total: true } }),
      db.product.aggregate({ _count: true }),
    ]);

    const result = {
      userCount: userStats._count,
      orderCount: orderStats._count,
      revenue: orderStats._sum.total ?? 0,
      productCount: productStats._count,
    };

    // 写入缓存
    await redis.set(cacheKey, JSON.stringify(result), 'EX', 300);
    return result;
  } catch (error) {
    logger.error('Dashboard stats failed', error);
    throw new InternalServerErrorException('获取统计数据失败');
  }
}

