// 3. 订单价格计算 — 传统编程
// 手写复杂的价格计算逻辑
function calculateOrderPrice(items: CartItem[], rules: PriceRule[]): number {
  let subtotal = items.reduce((sum, item) => sum + item.price * item.qty, 0);

  // 满减（不叠加，取最优）
  const bestDiscount = rules
    .filter(r => r.type === 'threshold' && subtotal >= r.threshold)
    .reduce((best, r) => r.discount > best ? r.discount : best, 0);
  subtotal -= bestDiscount;

  // 会员折扣（与满减叠加）
  subtotal *= rules.find(r => r.type === 'member')?.discount ?? 1;

  return Math.max(0, subtotal);
}

