// auth.module.ts
@Module({
  imports: [
    JwtModule.registerAsync({
      useFactory: () => ({
        secret: process.env.JWT_SECRET,
        signOptions: { expiresIn: '1h' },
      }),
    }),
    PrismaModule,
  ],
  controllers: [AuthController],
  providers: [AuthService, JwtStrategy],
})
export class AuthModule {}

// auth.service.ts
@Injectable()
export class AuthService {
  constructor(
    private prisma: PrismaService,
    private jwt: JwtService,
  ) {}

  async register(dto: RegisterDto) {
    // 检查邮箱唯一
    const exists = await this.prisma.user.findUnique({
      where: { email: dto.email },
    });
    if (exists) throw new ConflictException('邮箱已注册');

    // 加密密码
    const password = await bcrypt.hash(dto.password, 10);

    // 创建用户
    const user = await this.prisma.user.create({
      data: { email: dto.email, name: dto.name, password },
    });

    // 生成 token
    return this.generateToken(user.id, user.role);
  }

  async login(dto: LoginDto) {
    const user = await this.prisma.user.findUnique({
      where: { email: dto.email },
    });
    if (!user) throw new UnauthorizedException('认证失败');

    const valid = await bcrypt.compare(dto.password, user.password);
    if (!valid) throw new UnauthorizedException('认证失败');

    return this.generateToken(user.id, user.role);
  }

  private generateToken(userId: number, role: string) {
    const payload = { sub: userId, role };
    return {
      accessToken: this.jwt.sign(payload),
    };
  }
}

// roles.decorator.ts — 权限装饰器
export const Roles = (...roles: string[]) => SetMetadata('roles', roles);

// roles.guard.ts — 权限守卫
@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}
  canActivate(context: ExecutionContext): boolean {
    const required = this.reflector.get<string[]>('roles', context.getHandler());
    if (!required) return true;
    const { user } = context.switchToHttp().getRequest();
    return required.includes(user.role);
  }
}

concepts.content:
NestJS 接口开发流程：

1. 定义 DTO（数据传输对象）
   class CreateUserDto {
     @IsEmail() email: string;
     @MinLength(8) password: string;
   }

2. 创建 Controller
   @Controller("users')
   class UserController { ... }

3. 创建 Service
   @Injectable()
   class UserService { ... }

4. 创建 Module
   @Module({ controllers, providers })
   class UserModule {}

5. 统一响应格式
   { data: ..., message: '...', meta: { total, page } }

💡 Controller 只做参数接收和返回，逻辑放 Service

codeExamples.code:
// user.controller.ts
@ApiTags('用户')
@Controller('users')
@UseGuards(JwtAuthGuard)
export class UserController {
  constructor(private userService: UserService) {}

  @Get()
  @ApiOperation({ summary: '获取用户列表' })
  async findAll(
    @Query('page') page = 1,
    @Query('pageSize') pageSize = 20,
    @Query('role') role?: string,
  ) {
    const [users, total] = await this.userService.findAll({
      page: +page,
      pageSize: +pageSize,
      role,
    });
    return {
      data: users,
      meta: { total, page: +page, pageSize: +pageSize },
    };
  }

  @Post()
  @Roles('admin')
  @UseGuards(RolesGuard)
  @ApiOperation({ summary: '创建用户' })
  async create(@Body() dto: CreateUserDto) {
    const user = await this.userService.create(dto);
    return { data: user, message: '创建成功' };
  }

  @Get(':id')
  @ApiOperation({ summary: '获取用户详情' })
  async findOne(@Param('id', ParseIntPipe) id: number) {
    const user = await this.userService.findOne(id);
    if (!user) throw new NotFoundException('用户不存在');
    return { data: user };
  }
}

// user.service.ts
@Injectable()
export class UserService {
  constructor(private prisma: PrismaService) {}

  async findAll(params: { page: number; pageSize: number; role?: string }) {
    const where = params.role ? { role: params.role } : {};
    const [users, total] = await Promise.all([
      this.prisma.user.findMany({
        where,
        skip: (params.page - 1) * params.pageSize,
        take: params.pageSize,
        select: { id: true, email: true, name: true, role: true },
        orderBy: { createdAt: 'desc' },
      }),
      this.prisma.user.count({ where }),
    ]);
    return [users, total];
  }
}

